      % \\
      % \end{split}
   % \end{align*} 
   \end{align*}
With similar calculations as in  \cite{ACT2015} and using \eqref{CFL_LF}, we have $0\le  a^{k,n}_{i+1/2},  b^{k,n}_{i+1/2}\le 1/3,$ implying
